fn main() {
    proconio::input! {
        n: usize,
        mut a: [usize; n],
    }
    let s = b"";
    a.iter_mut().for_each(|ai| *ai -= 1);
    let mut buf = vec![0; n];
    let mut ans = (0..n).collect::<Vec<_>>();
    for &c in s.iter().rev() {
        if c == b'1' {
            for ansi in &mut ans {
                *ansi = a[*ansi];
            }
        }
        for i in 0..n {
            buf[i] = a[a[i]];
        }
        a.clone_from(&buf);
    }
    for &ansi in &ans {
        print!("{} ", ansi + 1);
    }
    println!();
}